import React, { useState } from 'react';
import { Control, Risk, Finding, Framework } from '../../types';
import { ISO_DOMAINS, ISO22301_DOMAINS, NIS2_DOMAINS, DORA_DOMAINS, GDPR_DOMAINS, SOC2_DOMAINS, HDS_DOMAINS, PCI_DSS_DOMAINS, NIST_CSF_DOMAINS } from '../../data/complianceData';
import { ChevronDown, ChevronRight, Paperclip, AlertTriangle, ShieldAlert, AlertOctagon } from '../../components/ui/Icons';
import { Skeleton } from '../../components/ui/Skeleton';
import { Tooltip as CustomTooltip } from '../../components/ui/Tooltip';
import { EmptyState } from '../../components/ui/EmptyState';
import { AgentVerificationIndicator } from './AgentVerificationBadge';

interface ComplianceListProps {
    controls: Control[];
    risks: Risk[];
    findings: Finding[];
    loading: boolean;
    currentFramework: Framework;
    selectedControlId?: string;
    onSelectControl: (control: Control) => void;
    filter?: string;
}

const getFrameworkStyles = (framework: Framework) => {
    switch (framework) {
        case 'ISO27001':
            return {
                accent: 'text-brand-600 dark:text-brand-400',
                bg: 'bg-brand-50 dark:bg-brand-800',
                border: 'border-brand-100 dark:border-brand-700',
                progress: 'bg-brand-600 shadow-brand-600/20'
            };
        case 'NIS2':
            return {
                accent: 'text-purple-600 dark:text-purple-400',
                bg: 'bg-purple-50 dark:bg-purple-900/20',
                border: 'border-purple-100 dark:border-purple-800/50',
                progress: 'bg-purple-600 shadow-purple-600/20'
            };
        case 'GDPR':
            return {
                accent: 'text-green-600 dark:text-green-400',
                bg: 'bg-green-50 dark:bg-green-900/20',
                border: 'border-green-100 dark:border-green-800/50',
                progress: 'bg-green-600 shadow-green-600/20'
            };
        case 'DORA':
            return {
                accent: 'text-yellow-600 dark:text-yellow-400',
                bg: 'bg-yellow-50 dark:bg-yellow-900/20',
                border: 'border-yellow-100 dark:border-yellow-800/50',
                progress: 'bg-yellow-600 shadow-yellow-600/20'
            };
        case 'ISO22301':
            return {
                accent: 'text-violet-600 dark:text-violet-400',
                bg: 'bg-violet-50 dark:bg-violet-900/20',
                border: 'border-violet-100 dark:border-violet-800/50',
                progress: 'bg-violet-600 shadow-violet-600/20'
            };
        case 'SOC2':
            return {
                accent: 'text-red-600 dark:text-red-400',
                bg: 'bg-red-50 dark:bg-red-900/20',
                border: 'border-red-100 dark:border-red-800',
                progress: 'bg-red-600 shadow-red-600/20'
            };
        case 'HDS':
            return {
                accent: 'text-blue-600 dark:text-blue-400',
                bg: 'bg-blue-50 dark:bg-blue-900/20',
                border: 'border-blue-100 dark:border-blue-800',
                progress: 'bg-blue-600 shadow-blue-600/20'
            };
        case 'PCI_DSS':
            return {
                accent: 'text-red-600 dark:text-red-400',
                bg: 'bg-red-50 dark:bg-red-900/20',
                border: 'border-red-100 dark:border-red-800',
                progress: 'bg-red-600 shadow-red-600/20'
            };
        case 'NIST_CSF':
            return {
                accent: 'text-yellow-600 dark:text-yellow-400',
                bg: 'bg-yellow-50 dark:bg-yellow-900/20',
                border: 'border-yellow-100 dark:border-yellow-800/50',
                progress: 'bg-yellow-600 shadow-yellow-600/20'
            };
        default:
            return {
                accent: 'text-brand-600 dark:text-brand-400',
                bg: 'bg-brand-50 dark:bg-brand-800',
                border: 'border-brand-100 dark:border-brand-700',
                progress: 'bg-brand-600 shadow-brand-600/20'
            };
    }
};

export const ComplianceList: React.FC<ComplianceListProps> = ({
    controls,
    risks,
    findings,
    loading,
    currentFramework,
    selectedControlId,
    onSelectControl,
    filter
}) => {
    const [expandedDomains, setExpandedDomains] = useState<string[]>([]);

    const toggleDomain = (domainId: string) => {
        setExpandedDomains(prev =>
            prev.includes(domainId) ? prev.filter(id => id !== domainId) : [...prev, domainId]
        );
    };

    const getDomainStats = (prefix: string) => {
        const domainControls = controls.filter(c => c.code.startsWith(prefix));
        const total = domainControls.length;
        const implemented = domainControls.filter(c => c.status === 'Implémenté').length;
        const partial = domainControls.filter(c => c.status === 'Partiel').length;
        // Progress: implemented is 100%, partial is 50%
        const progress = total > 0 ? Math.round(((implemented + (partial * 0.5)) / total) * 100) : 0;
        return { total, implemented, partial, progress };
    };

    let domains: { id: string, title: string, description: string }[] = [];
    switch (currentFramework) {
        case 'ISO27001': domains = ISO_DOMAINS; break;
        case 'ISO22301': domains = ISO22301_DOMAINS; break;
        case 'NIS2': domains = NIS2_DOMAINS; break;
        case 'DORA': domains = DORA_DOMAINS; break;
        case 'GDPR': domains = GDPR_DOMAINS; break;
        case 'SOC2': domains = SOC2_DOMAINS; break;
        case 'HDS': domains = HDS_DOMAINS; break;
        case 'PCI_DSS': domains = PCI_DSS_DOMAINS; break;
        case 'NIST_CSF': domains = NIST_CSF_DOMAINS; break;
    }

    if (loading) {
        return (
            <div className="space-y-4">
                {[1, 2, 3, 4].map(i => (
                    <div key={`skel-${i}`} className="glass-premium p-6 flex items-center gap-4 rounded-4xl">
                        <Skeleton className="w-12 h-12 rounded-2xl" />
                        <div className="space-y-2 flex-1">
                            <Skeleton className="h-5 w-48" />
                            <Skeleton className="h-4 w-full max-w-md" />
                        </div>
                    </div>
                ))}
            </div>
        );
    }

    if (controls.length === 0) {
        return (
            <EmptyState
                icon={ShieldAlert}
                title="Aucun contrôle trouvé"
                description={filter ? "Aucun contrôle ne correspond à votre recherche." : "Les contrôles n'ont pas été chargés."}
            />
        );
    }

    return (
        <div className="space-y-4">
            {domains.map(domain => {
                const domainControls = controls.filter(c => c.code.startsWith(domain.id));
                // Hide domain if no controls match filter
                if (domainControls.length === 0) return null;

                const stats = getDomainStats(domain.id);
                // Expand if user filtered or manually expanded
                const isExpanded = expandedDomains.includes(domain.id) || (filter && filter.length > 0);

                const fwStyles = getFrameworkStyles(currentFramework);

                return (
                    <div key={domain.id} className="glass-premium rounded-3xl shadow-sm overflow-hidden transition-all duration-300 hover:shadow-apple group relative">
                        <div className="absolute inset-0 bg-gradient-to-br from-white/40 to-transparent dark:from-white/5 pointer-events-none" />
                        <div
                            data-testid={`domain-header-${domain.id}`}
                            onClick={() => toggleDomain(domain.id)}
                            className={`p-4 md:p-8 flex flex-col md:flex-row md:items-center justify-between cursor-pointer transition-colors gap-4 relative z-10 ${isExpanded ? 'bg-slate-50/80 dark:bg-white/5' : 'hover:bg-slate-50 dark:hover:bg-white/5'}`}
                        >
                            <div className="flex items-center gap-5 flex-1 min-w-0">
                                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg border shrink-0 shadow-sm shadow-black/5 transition-all group-hover:scale-110 ${fwStyles.bg} ${fwStyles.accent} ${fwStyles.border}`}>
                                    {domain.id.split('.')[1] || domain.id}
                                </div>
                                <div className="min-w-0">
                                    <h3 className="text-lg font-bold text-slate-900 dark:text-white leading-tight truncate pr-2">{domain.title}</h3>
                                    <p className="text-sm text-slate-600 dark:text-muted-foreground font-medium mt-1 truncate">{domain.description} • <span className="text-slate-700 dark:text-muted-foreground">{stats.total} contrôles</span></p>
                                </div>
                            </div>
                            <div className="flex items-center justify-between md:justify-end gap-3 md:gap-8 w-full md:w-auto pl-[4.25rem] md:pl-0">
                                <div className="w-full md:w-40">
                                    <div className="flex justify-between text-xs font-bold text-slate-600 dark:text-muted-foreground mb-1.5">
                                        <span>Progression</span>
                                        <span className="text-slate-900 dark:text-white">{stats.progress}%</span>
                                    </div>
                                    <div className="w-full bg-slate-100 dark:bg-slate-800/50 rounded-full h-2 overflow-hidden shadow-inner">
                                        <div className={`h-full rounded-full transition-all duration-700 ease-in-out ${stats.progress === 100 ? 'bg-success-text shadow-glow shadow-success-text/20' : `${fwStyles.progress} shadow-glow`}`} style={{ width: `${stats.progress}%` }}></div>
                                    </div>
                                </div>
                                <div className={`p-2 rounded-xl transition-all duration-500 shrink-0 ${isExpanded ? 'bg-white dark:bg-white/10 shadow-apple-sm rotate-180 text-slate-900 dark:text-white ring-1 ring-black/5' : 'text-slate-400 group-hover:text-slate-600 group-hover:bg-slate-100 dark:hover:bg-slate-800 dark:group-hover:bg-white/5'}`}>
                                    <ChevronDown className="h-5 w-5" />
                                </div>
                            </div>
                        </div>

                        {isExpanded && (
                            <div className="p-4 bg-slate-50/50 dark:bg-black/20 backdrop-blur-sm border-t border-slate-100 dark:border-white/5 relative z-10">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                    {domainControls.map(control => {
                                        const riskCount = risks.filter(r => r.mitigationControlIds?.includes(control.id)).length;
                                        const findingsCount = findings.filter(f => f.relatedControlId === control.id && f.status === 'Ouvert').length;
                                        const isActive = selectedControlId === control.id;

                                        return (
                                            <div
                                                key={control.id}
                                                data-testid={`control-row-${control.code}`}
                                                onClick={() => {

                                                    onSelectControl(control);
                                                }}
                                                className={`group relative p-4 rounded-2xl border transition-all duration-200 cursor-pointer overflow-hidden hover:shadow-md ${isActive
                                                    ? 'bg-brand-50 border-brand-200 dark:bg-brand-800 dark:border-brand-800'
                                                    : 'bg-white dark:bg-white/5 border-slate-200 dark:border-white/5 hover:border-brand-200 dark:hover:border-brand-600'
                                                    }`}
                                            >
                                                <div className="flex items-start justify-between gap-4">
                                                    <div className="flex items-start gap-3 min-w-0">
                                                        <div className={`shrink-0 flex items-center justify-center w-10 h-10 rounded-2xl text-xs font-black transition-all shadow-sm ${isActive ? 'bg-brand-600 text-white' : `bg-slate-100 dark:bg-white/10 text-slate-500 dark:text-slate-300 group-hover:${fwStyles.bg} group-hover:${fwStyles.accent} border border-transparent group-hover:${fwStyles.border}`}`}>
                                                            {control.code.split('.').slice(1).join('.') || control.code}
                                                        </div>
                                                        <div className="min-w-0 pt-0.5">
                                                            <h4 className={`text-sm font-bold truncate pr-2 leading-tight ${isActive ? 'text-brand-900 dark:text-brand-100' : 'text-slate-900 dark:text-white'}`}>
                                                                {control.name}
                                                            </h4>
                                                            <p className="text-[11px] text-slate-500 dark:text-slate-300 font-mono mt-0.5 uppercase tracking-wider">{control.code}</p>
                                                        </div>
                                                    </div>
                                                    <div className={`shrink-0 px-2.5 py-1 rounded-xl text-[11px] font-bold uppercase tracking-wide border shadow-sm whitespace-nowrap ${control.status === 'Implémenté' ? 'text-success-text bg-success-bg border-success-border/50' :
                                                        control.status === 'Partiel' ? 'text-warning-text bg-warning-bg border-warning-border/50' :
                                                            control.status === 'Non applicable' ? 'text-slate-500 bg-slate-100 border-slate-200 dark:bg-slate-800/50 dark:text-slate-300 dark:border-slate-700' :
                                                                'text-slate-600 bg-white border-slate-200 dark:bg-slate-800 dark:text-slate-300 dark:border-slate-700'
                                                        }`}>
                                                        {control.status}
                                                    </div>
                                                </div>

                                                <div className="flex items-center gap-2 mt-4 pl-[3.25rem]">
                                                    {control.evidenceIds && control.evidenceIds.length > 0 ? (
                                                        <span className="flex items-center text-success-text bg-success-bg px-2 py-1 rounded-lg text-[11px] font-bold border border-success-border/30">
                                                            <Paperclip className="h-3 w-3 mr-1.5" />
                                                            {control.evidenceIds.length}
                                                        </span>
                                                    ) : (control.status === 'Implémenté') ? (
                                                        <CustomTooltip content="Preuve obligatoire manquante">
                                                            <span className="flex items-center text-warning-text bg-warning-bg px-2 py-1 rounded-lg text-[11px] font-bold border border-warning-border/30">
                                                                <AlertTriangle className="h-3 w-3 mr-1.5" />
                                                                Manquante
                                                            </span>
                                                        </CustomTooltip>
                                                    ) : null}

                                                    {riskCount > 0 && (
                                                        <span className="flex items-center text-info-text bg-info-bg px-2 py-1 rounded-lg text-[11px] font-bold border border-info-border/30">
                                                            <ShieldAlert className="h-3 w-3 mr-1.5" />
                                                            {riskCount}
                                                        </span>
                                                    )}

                                                    {findingsCount > 0 && (
                                                        <span className="flex items-center text-error-text bg-error-bg px-2 py-1 rounded-lg text-[11px] font-bold border border-error-border/30">
                                                            <AlertOctagon className="h-3 w-3 mr-1.5" />
                                                            {findingsCount}
                                                        </span>
                                                    )}

                                                    {/* Agent Verification Indicator */}
                                                    <AgentVerificationIndicator
                                                        controlId={control.code}
                                                        framework={currentFramework}
                                                    />

                                                    <div className="flex-1" />

                                                    <div className={`text-slate-300 dark:text-slate-300 transition-transform duration-300 group-hover:translate-x-1 ${isActive ? 'text-brand-300 dark:text-brand-700' : ''}`}>
                                                        <ChevronRight className="h-4 w-4" />
                                                    </div>
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        )}
                    </div>
                );
            })}
        </div>
    );
};

import { useState, useEffect, useCallback } from 'react';
import { collection, addDoc, query, orderBy, limit, getDocs, serverTimestamp, Timestamp } from 'firebase/firestore';
import { db } from '../../firebase';
import { Control, Risk, SoAVersion, SoAControlSnapshot, Framework } from '../../types';
import { Badge } from '../ui/Badge';
import { Button } from '../ui/button';
import { Download, AlertTriangle, FileText, Save, History, Clock, User, ChevronRight, X } from '../ui/Icons';
import { useStore } from '../../store';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import { cn } from '../../lib/utils';
import { ErrorLogger } from '../../services/errorLogger';

interface SoAViewProps {
    controls: Control[];
    risks: Risk[];
    framework?: Framework;
    handlers: {
        updateControl: (id: string, updates: Partial<Control>) => Promise<boolean>;
        handleApplicabilityChange: (control: Control, isApplicable: boolean) => Promise<void>;
        updateJustification: (control: Control, text: string) => Promise<void>;
    };
    onSeed?: () => Promise<void>;
}

export const SoAView: React.FC<SoAViewProps> = ({ controls, risks, framework = 'ISO27001', handlers, onSeed }) => {
    const { user, addToast } = useStore();
    const [versions, setVersions] = useState<SoAVersion[]>([]);
    const [showHistory, setShowHistory] = useState(false);
    const [savingVersion, setSavingVersion] = useState(false);
    const [loadingVersions, setLoadingVersions] = useState(false);
    const [selectedVersion, setSelectedVersion] = useState<SoAVersion | null>(null);

    // Calculate current stats
    const currentStats = {
        totalControls: controls.length,
        applicableControls: controls.filter(c => c.applicability !== 'Non applicable' && c.status !== 'Non applicable').length,
        implementedControls: controls.filter(c => c.status === 'Implémenté').length,
        partialControls: controls.filter(c => c.status === 'Partiel').length,
    };

    // Load version history
    const loadVersions = useCallback(async () => {
        if (!user?.organizationId) return;
        setLoadingVersions(true);
        try {
            const versionsRef = collection(db, 'organizations', user.organizationId, 'soaVersions');
            const q = query(versionsRef, orderBy('generatedAt', 'desc'), limit(20));
            const snapshot = await getDocs(q);
            const loadedVersions = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data(),
                generatedAt: doc.data().generatedAt instanceof Timestamp
                    ? doc.data().generatedAt.toDate().toISOString()
                    : doc.data().generatedAt
            })) as SoAVersion[];
            setVersions(loadedVersions);
        } catch (error) {
            ErrorLogger.error(error, 'SoAView.loadVersions');
        } finally {
            setLoadingVersions(false);
        }
    }, [user?.organizationId]);

    useEffect(() => {
        loadVersions();
    }, [loadVersions]);

    // Save current state as a new version
    const saveVersion = async () => {
        if (!user?.organizationId || !user?.uid) {
            addToast('Erreur: utilisateur non connecté', 'error');
            return;
        }

        setSavingVersion(true);
        try {
            const snapshot: SoAControlSnapshot[] = controls.map(c => ({
                code: c.code,
                name: c.name,
                applicability: c.applicability || (c.status === 'Non applicable' ? 'Non applicable' : 'Applicable'),
                justification: c.justification || '',
                status: c.status,
                risksCount: c.relatedRiskIds?.filter(id => risks.some(r => r.id === id)).length || 0,
                evidenceCount: c.evidenceIds?.length || 0,
            }));

            const newVersion = {
                organizationId: user.organizationId,
                framework,
                version: versions.length + 1,
                generatedAt: serverTimestamp(),
                generatedBy: user.uid,
                generatedByName: user.displayName || user.email || 'Unknown',
                controlsSnapshot: snapshot,
                stats: currentStats,
            };

            const versionsRef = collection(db, 'organizations', user.organizationId, 'soaVersions');
            await addDoc(versionsRef, newVersion);

            addToast('Version SoA sauvegardée', 'success');
            await loadVersions(); // Refresh the list
        } catch (error) {
            ErrorLogger.error(error, 'SoAView.saveVersion');
            addToast('Erreur lors de la sauvegarde', 'error');
        } finally {
            setSavingVersion(false);
        }
    };

    // Export PDF (current or selected version)
    const exportPDF = (versionData?: SoAVersion) => {
        const doc = new jsPDF();
        const isHistorical = !!versionData;
        const title = isHistorical
            ? `Statement of Applicability (SoA) - ${versionData.framework} - v${versionData.version}`
            : `Statement of Applicability (SoA) - ${framework}`;

        doc.text(title, 14, 20);

        if (isHistorical && versionData) {
            doc.setFontSize(10);
            doc.text(`Généré le: ${new Date(versionData.generatedAt).toLocaleDateString('fr-FR')}`, 14, 28);
            doc.text(`Par: ${versionData.generatedByName}`, 14, 34);
        }

        const dataSource = isHistorical && versionData
            ? versionData.controlsSnapshot.map(c => [
                c.code,
                c.name,
                c.applicability,
                c.justification || '-',
                c.status,
                c.risksCount.toString()
            ])
            : controls.map(c => [
                c.code,
                c.name,
                c.applicability || (c.status === 'Non applicable' ? 'Non applicable' : 'Applicable'),
                c.justification || '-',
                c.status,
                (c.relatedRiskIds?.length || 0).toString()
            ]);

        autoTable(doc, {
            startY: isHistorical ? 42 : 30,
            head: [['Code', 'Nom', 'Applicabilité', 'Justification', 'Statut', 'Risques']],
            body: dataSource,
        });

        const filename = isHistorical
            ? `SoA_${versionData?.framework}_v${versionData?.version}.pdf`
            : 'SoA_Report.pdf';
        doc.save(filename);
        addToast('Export SoA généré', 'success');
    };

    // Display data (current or selected historical version)
    const displayControls = selectedVersion
        ? selectedVersion.controlsSnapshot.map((snap, idx) => ({
            id: `snap-${idx}`,
            code: snap.code,
            name: snap.name,
            applicability: snap.applicability,
            justification: snap.justification,
            status: snap.status,
            linkedRisksCount: snap.risksCount,
            evidenceCount: snap.evidenceCount,
            isHistorical: true,
        }))
        : controls.map(c => ({
            id: c.id,
            code: c.code,
            name: c.name,
            description: c.description,
            applicability: c.applicability || (c.status === 'Non applicable' ? 'Non applicable' : 'Applicable'),
            justification: c.justification,
            status: c.status,
            linkedRisksCount: c.relatedRiskIds?.filter(id => risks.some(r => r.id === id)).length || 0,
            evidenceCount: c.evidenceIds?.length || 0,
            maturity: c.maturity,
            isHistorical: false,
            control: c,
        }));

    return (
        <div className="space-y-4">
            {/* Header with actions */}
            <div className="flex flex-wrap items-center justify-between gap-4">
                <div className="flex items-center gap-2">
                    {selectedVersion && (
                        <div className="flex items-center gap-2 px-3 py-1.5 bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800 rounded-lg">
                            <History className="h-4 w-4 text-yellow-600 dark:text-yellow-400" />
                            <span className="text-sm font-medium text-yellow-700 dark:text-yellow-300">
                                Version {selectedVersion.version} - {new Date(selectedVersion.generatedAt).toLocaleDateString('fr-FR')}
                            </span>
                            <button
                                onClick={() => setSelectedVersion(null)}
                                className="ml-2 p-0.5 hover:bg-yellow-200 dark:hover:bg-yellow-800 rounded"
                            >
                                <X className="h-3 w-3 text-yellow-600 dark:text-yellow-400" />
                            </button>
                        </div>
                    )}
                </div>
                <div className="flex gap-2">
                    <Button
                        variant="outline"
                        onClick={() => setShowHistory(!showHistory)}
                        className="relative"
                    >
                        <History className="h-4 w-4 mr-2" />
                        Historique
                        {versions.length > 0 && (
                            <span className="ml-1.5 px-1.5 py-0.5 text-xs bg-brand-100 dark:bg-brand-900 text-brand-700 dark:text-brand-300 rounded-full">
                                {versions.length}
                            </span>
                        )}
                    </Button>
                    {!selectedVersion && (
                        <Button
                            variant="outline"
                            onClick={saveVersion}
                            disabled={savingVersion || controls.length === 0}
                        >
                            <Save className="h-4 w-4 mr-2" />
                            {savingVersion ? 'Sauvegarde...' : 'Sauvegarder version'}
                        </Button>
                    )}
                    <Button variant="outline" onClick={() => exportPDF(selectedVersion || undefined)}>
                        <Download className="h-4 w-4 mr-2" />
                        Exporter SoA (PDF)
                    </Button>
                </div>
            </div>

            {/* Version History Panel */}
            {showHistory && (
                <div className="glass-panel rounded-xl p-4 space-y-3">
                    <div className="flex items-center justify-between">
                        <h3 className="font-semibold text-slate-900 dark:text-white flex items-center gap-2">
                            <History className="h-5 w-5 text-brand-600 dark:text-brand-400" />
                            Historique des versions
                        </h3>
                        <button
                            onClick={() => setShowHistory(false)}
                            className="p-1 hover:bg-slate-100 dark:hover:bg-slate-800 rounded"
                        >
                            <X className="h-4 w-4 text-slate-500" />
                        </button>
                    </div>

                    {loadingVersions ? (
                        <div className="py-4 text-center text-slate-500">Chargement...</div>
                    ) : versions.length === 0 ? (
                        <div className="py-4 text-center text-slate-500">
                            Aucune version sauvegardée. Cliquez sur "Sauvegarder version" pour créer un snapshot.
                        </div>
                    ) : (
