                                            </td>
                                        )}
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { HeartPulse, LayoutDashboard, Server, ClipboardCheck, Edit, Trash2 } from '../ui/Icons';
import { slideUpVariants } from '../ui/animationVariants';
import { CardSkeleton } from '../ui/Skeleton';
import { EmptyState } from '../ui/EmptyState';
import { BusinessProcess, UserProfile } from '../../types';
import { getUserAvatarUrl } from '../../utils/avatarUtils';

interface ContinuityBIAProps {
    processes: BusinessProcess[];
    loading: boolean;
    viewMode: 'grid' | 'list';
    onOpenInspector: (proc: BusinessProcess) => void;
    onNewProcess: () => void;
    onDelete?: (id: string) => void;
    users?: UserProfile[];
}

export const ContinuityBIA: React.FC<ContinuityBIAProps> = ({ processes, loading, viewMode, onOpenInspector, onNewProcess, onDelete, users }) => {
    const [deletingIds, setDeletingIds] = useState<Set<string>>(new Set());

    const handleDelete = async (id: string) => {
        if (!onDelete || deletingIds.has(id)) return;
        setDeletingIds(prev => new Set(prev).add(id));
        try {
            await onDelete(id);
        } finally {
            setDeletingIds(prev => {
                const next = new Set(prev);
                next.delete(id);
                return next;
            });
        }
    };

    const getPriorityColor = (p: string) => {
        switch (p) {
            case 'Critique': return 'bg-red-50 text-red-700 dark:text-red-400 border-red-100 dark:bg-red-900/20 dark:text-red-400 dark:border-red-900/30';
            case 'Elevée': return 'bg-orange-50 text-orange-700 dark:text-orange-400 border-orange-100 dark:bg-orange-900/20 dark:text-orange-400 dark:border-orange-900/30';
            case 'Moyenne': return 'bg-yellow-50 text-yellow-700 border-yellow-100 dark:bg-yellow-900/20 dark:text-yellow-400 dark:border-yellow-900/30';
            default: return 'bg-blue-50 dark:bg-slate-900 text-blue-700 dark:text-blue-400 border-blue-100 dark:bg-slate-900/20 dark:text-blue-400 dark:border-blue-900/30';
        }
    };

    if (loading) return <CardSkeleton count={6} />;

    if (processes.length === 0) {
        return (
            <div className="col-span-full">
                <EmptyState
                    icon={HeartPulse}
                    title="Aucun processus défini"
                    description="Commencez par définir vos processus critiques pour l'analyse d'impact (BIA)."
                    actionLabel="Nouveau Processus"
                    onAction={onNewProcess}
                />
            </div>
        );
    }

    if (viewMode === 'list') {
        return (
            <div className="glass-panel rounded-3xl overflow-hidden shadow-sm border border-white/50 dark:border-white/5 animate-in fade-in duration-500">
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-slate-50/80 dark:bg-slate-900/50 border-b border-slate-100 dark:border-white/5 text-slate-500 dark:text-slate-300 font-bold uppercase text-[11px] tracking-widest backdrop-blur-sm">
                            <tr>
                                <th className="px-8 py-5">Processus</th>
                                <th className="px-6 py-5">Priorité</th>
                                <th className="px-6 py-5">RTO</th>
                                <th className="px-6 py-5">RPO</th>
                                <th className="px-6 py-5">Responsable</th>
                                <th className="px-6 py-5">Dernier Test</th>
                                <th className="px-6 py-5 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-white/5">
                            {processes.map(proc => {
                                const lastTest = proc.lastTestDate ? new Date(proc.lastTestDate) : null;
                                const isOverdue = lastTest ? (new Date().getTime() - lastTest.getTime() > 31536000000) : true;
                                const ownerUser = users?.find(u => u.displayName === proc.owner || u.email === proc.owner);

                                return (
                                    <tr
                                        key={proc.id}
                                        onClick={() => onOpenInspector(proc)}
                                        className="hover:bg-white/60 dark:hover:bg-slate-800/40 transition-colors cursor-pointer group focus:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-brand-500"
                                        tabIndex={0}
                                        role="button"
                                        onKeyDown={(e) => {
                                            if (e.key === 'Enter' || e.key === ' ') {
                                                e.preventDefault();
                                                onOpenInspector(proc);
                                            }
                                        }}
                                    >
                                        <td className="px-8 py-5 text-slate-900 dark:text-white font-bold">
                                            {proc.name}
                                        </td>
                                        <td className="px-6 py-5">
                                            <span className={`px-3 py-1 rounded-lg text-[11px] font-bold uppercase tracking-wider border shadow-sm ${getPriorityColor(proc.priority)}`}>
                                                {proc.priority}
                                            </span>
                                        </td>
                                        <td className="px-6 py-5 font-mono text-slate-600 dark:text-slate-300 font-bold">{proc.rto}</td>
                                        <td className="px-6 py-5 font-mono text-slate-600 dark:text-slate-300 font-bold">{proc.rpo}</td>
                                        <td className="px-6 py-5 text-slate-600 dark:text-muted-foreground">
                                            <div className="flex items-center gap-2">
                                                <img
                                                    src={getUserAvatarUrl(ownerUser?.photoURL, ownerUser?.role)}
                                                    alt={proc.owner}
                                                    className="w-5 h-5 rounded-full object-cover bg-slate-100 dark:bg-slate-800"
                                                    onError={(e) => {
                                                        const target = e.target as HTMLImageElement;
                                                        target.src = getUserAvatarUrl(null, ownerUser?.role);
                                                    }}
                                                />
                                                <span>{proc.owner}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-5">
                                            <span className={`font-bold text-xs px-2 py-1 rounded ${isOverdue ? 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400' : 'bg-green-50 dark:bg-green-900/20 text-green-600 dark:text-green-400'}`}>
                                                {proc.lastTestDate ? new Date(proc.lastTestDate).toLocaleDateString() : 'Jamais'}
                                            </span>
                                        </td>
                                        <td className="px-6 py-5 text-right">
                                            <div className="flex items-center justify-end gap-2">
                                                <button
                                                    onClick={(e) => { e.stopPropagation(); onOpenInspector(proc); }}
                                                    className="p-2 text-slate-500 dark:text-slate-300 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/30 dark:hover:bg-blue-900/20 rounded-lg transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-500"
                                                    title="Modifier"
                                                >
                                                    <Edit className="h-4 w-4" />
                                                </button>
                                                {onDelete && (
                                                    <button
                                                        onClick={(e) => { e.stopPropagation(); handleDelete(proc.id); }}
                                                        disabled={deletingIds.has(proc.id)}
                                                        className="p-2 text-slate-500 dark:text-slate-300 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 dark:hover:bg-red-900/20 rounded-lg transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-red-500 disabled:bg-slate-200 disabled:text-slate-500 disabled:border-slate-300 disabled:cursor-not-allowed dark:disabled:bg-slate-700 dark:disabled:text-slate-400 dark:disabled:border-slate-600"
                                                        title={deletingIds.has(proc.id) ? "Suppression..." : "Supprimer"}
                                                    >
                                                        <Trash2 className="h-4 w-4" />
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        );
    }

    return (
        <motion.div
            variants={slideUpVariants}
            initial="initial"
            animate="visible"
            className="grid grid-cols-1 lg:grid-cols-2 xl:grid-cols-3 gap-6"
        >
            {processes.map(proc => {
                const lastTest = proc.lastTestDate ? new Date(proc.lastTestDate) : null;
                const isOverdue = lastTest ? (new Date().getTime() - lastTest.getTime() > 31536000000) : true; // 1 year
                const ownerUser = users?.find(u => u.displayName === proc.owner || u.email === proc.owner);

                return (
                    <div
                        key={proc.id}
                        onClick={() => onOpenInspector(proc)}
                        onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onOpenInspector(proc); } }}
                        role="button"
                        tabIndex={0}
                        aria-label={`Ouvrir le processus ${proc.name}`}
                        className="glass-panel rounded-3xl p-7 shadow-sm hover:shadow-apple transition-all duration-300 hover:-translate-y-1 relative group flex flex-col cursor-pointer border border-white/50 dark:border-white/5"
                    >
                        <div className="flex justify-between items-start mb-5">
                            <div className="p-3 bg-rose-50 dark:bg-slate-800 rounded-2xl text-rose-600 shadow-inner">
                                <HeartPulse className="h-6 w-6" />
                            </div>
                            <span className={`px-3 py-1 rounded-lg text-[11px] font-bold uppercase tracking-wider border shadow-sm ${getPriorityColor(proc.priority)}`}>
                                {proc.priority}
                            </span>
                        </div>

                        <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-2 leading-tight">{proc.name}</h3>
                        <p className="text-sm text-slate-600 dark:text-muted-foreground mb-6 line-clamp-2 flex-1 leading-relaxed">{proc.description}</p>

                        <div className="grid grid-cols-2 gap-4 mb-6">
                            <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-2xl border border-slate-100 dark:border-white/5 text-center">
                                <span className="text-[11px] text-slate-500 dark:text-slate-300 uppercase font-bold block mb-1">RTO (Temps)</span>
                                <span className="text-3xl font-black text-slate-800 dark:text-slate-200 dark:text-white">{proc.rto}</span>
                            </div>
                            <div className="bg-slate-50 dark:bg-slate-800/50 p-3 rounded-2xl border border-slate-100 dark:border-white/5 text-center">
                                <span className="text-[11px] text-slate-500 dark:text-slate-300 uppercase font-bold block mb-1">RPO (Données)</span>
                                <span className="text-3xl font-black text-slate-800 dark:text-slate-200 dark:text-white">{proc.rpo}</span>
                            </div>
                        </div>

                        <div className="space-y-3 pt-4 border-t border-dashed border-slate-200 dark:border-white/10">
                            <div className="flex items-center justify-between text-xs">
                                <span className="flex items-center font-bold text-slate-500 dark:text-slate-300 uppercase tracking-wide"><LayoutDashboard className="h-3 w-3 mr-1.5" /> Responsable</span>
                                <span className="font-bold text-slate-700 dark:text-slate-200 truncate max-w-[150px] flex items-center gap-2">
                                    <img
                                        src={getUserAvatarUrl(ownerUser?.photoURL, ownerUser?.role)}
                                        alt={proc.owner}
                                        className="w-4 h-4 rounded-full object-cover bg-slate-100 dark:bg-slate-800"
                                        onError={(e) => {
                                            const target = e.target as HTMLImageElement;
                                            target.src = getUserAvatarUrl(null, ownerUser?.role);
                                        }}
                                    />
                                    {proc.owner}
                                </span>
                            </div>
                            <div className="flex items-center justify-between text-xs">
                                <span className="flex items-center font-bold text-slate-500 dark:text-slate-300 uppercase tracking-wide"><Server className="h-3 w-3 mr-1.5" /> Dépendances</span>
                                <span className="font-bold text-slate-700 dark:text-slate-200">{proc.supportingAssetIds?.length || 0} actifs</span>
                            </div>
                            <div className="flex items-center justify-between text-xs">
                                <span className="flex items-center font-bold text-slate-500 dark:text-slate-300 uppercase tracking-wide"><ClipboardCheck className="h-3 w-3 mr-1.5" /> Dernier Test</span>
                                <span className={`font-bold px-2 py-0.5 rounded ${isOverdue ? 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400' : 'bg-green-50 dark:bg-green-900/20 text-green-600 dark:text-green-400'}`}>
                                    {proc.lastTestDate ? new Date(proc.lastTestDate).toLocaleDateString() : 'Jamais'}
                                </span>
                            </div>
                        </div>
                    </div>
                )
            })}
        </motion.div>
    );
};

import React, { useState } from 'react';
import { useStore } from '../../store';
import { Edit2, Trash2, Loader2, Activity, Server, Zap, History, HeartPulse } from '../ui/Icons';
import { Button } from '../ui/button';
import { BusinessProcess, Asset, Supplier, Risk, BcpDrill, UserProfile } from '../../types';
import { getUserAvatarUrl } from '../../utils/avatarUtils';
import { InspectorLayout } from '../ui/InspectorLayout';
import { Badge } from '../ui/Badge';
import { TimelineView } from '../shared/TimelineView';
import { ProcessGeneralDetails } from './inspector/ProcessGeneralDetails';
import { ProcessDependencies } from './inspector/ProcessDependencies';
import { ProcessDrills } from './inspector/ProcessDrills';

interface ProcessInspectorProps {
    process: BusinessProcess | null;
    isOpen: boolean;
    onClose: () => void;
    onEdit: (p: BusinessProcess) => void;
    onDelete: (id: string) => void;
    assets: Asset[];
    suppliers: Supplier[];
    risks: Risk[];
    drills: BcpDrill[];
    users?: UserProfile[];
}

export const ProcessInspector: React.FC<ProcessInspectorProps> = ({
    process, isOpen, onClose, onEdit, onDelete, assets, suppliers, risks, drills, users
}) => {
    const { t } = useStore();
    // Note: 'any' cast used for setInspectorTab to avoid strict generic matching issues with the layout component,
    // though the types align.
    const [inspectorTab, setInspectorTab] = useState<'details' | 'dependencies' | 'drills' | 'history'>('details');
    const [isDeleting, setIsDeleting] = useState(false);

    const handleDelete = async () => {
        if (!process || isDeleting) return;
        setIsDeleting(true);
        try {
            await onDelete(process.id);
        } finally {
            setIsDeleting(false);
        }
    };

    if (!process) return null;

    const linkedAssets = assets.filter(a => process.supportingAssetIds?.includes(a.id));
    const linkedSuppliers = suppliers.filter(s => process.supplierIds?.includes(s.id));
    const linkedRisks = risks.filter(r => process.relatedRiskIds?.includes(r.id));
    const ownerUser = users?.find(u => u.displayName === process.owner || u.email === process.owner);

    const handleClose = () => {
        setInspectorTab('details');
        onClose();
    };

    const tabs = [
        { id: 'details', label: t('common.overview'), icon: Activity },
        { id: 'dependencies', label: t('common.dependencies'), icon: Server },
        { id: 'drills', label: t('continuity.tabs.drills'), icon: Zap },
        { id: 'history', label: t('common.history'), icon: History },
    ];

    return (
        <InspectorLayout
            isOpen={isOpen}
            onClose={handleClose}
            title={process.name}
            subtitle={
                <div className="flex items-center gap-2">
                    <span className="text-slate-500 dark:text-slate-400">{t('common.managedBy')}</span>
                    <div className="flex items-center gap-2">
                        <img
                            src={getUserAvatarUrl(ownerUser?.photoURL, ownerUser?.role)}
                            alt={process.owner}
                            className="w-5 h-5 rounded-full object-cover bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700"
                            onError={(e) => {
                                const target = e.target as HTMLImageElement;
                                target.src = getUserAvatarUrl(null, ownerUser?.role);
                            }}
                        />
                        <span className="font-medium text-slate-700 dark:text-slate-300 dark:text-muted-foreground">
                            {process.owner}
                        </span>
                    </div>
                </div>
            }
            icon={HeartPulse}
            statusBadge={
                <Badge
                    status={
                        process.priority === 'Critique' ? 'error' :
                            process.priority === 'Élevée' ? 'warning' :
                                'info'
                    }
                >
                    {process.priority}
                </Badge>
            }
            tabs={tabs}
            activeTab={inspectorTab}
            onTabChange={(id) => setInspectorTab(id as 'details' | 'dependencies' | 'drills' | 'history')}
            actions={
                <div className="flex gap-2">
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => onEdit(process)}
                        className="text-muted-foreground hover:text-brand-600 hover:bg-brand-50 dark:hover:bg-brand-800"
                        aria-label="Modifier le processus"
                    >
                        <Edit2 className="w-5 h-5" />
                    </Button>
                    <Button
                        variant="ghost"
                        size="icon"
                        onClick={handleDelete}
                        disabled={isDeleting}
                        className="text-muted-foreground hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/30 dark:hover:bg-red-900/20"
                        aria-label={isDeleting ? "Suppression en cours" : "Supprimer le processus"}
                    >
                        {isDeleting ? <Loader2 className="w-5 h-5 animate-spin" /> : <Trash2 className="w-5 h-5" />}
                    </Button>
                </div>
            }
        >
            <div className="p-6 md:p-8 space-y-8 bg-slate-50/50 dark:bg-transparent min-h-full">
                {inspectorTab === 'details' && (
                    <ProcessGeneralDetails process={process} />
                )}

                {inspectorTab === 'dependencies' && (
                    <ProcessDependencies
                        linkedAssets={linkedAssets}
                        linkedSuppliers={linkedSuppliers}
                        linkedRisks={linkedRisks}
                    />
                )}

                {inspectorTab === 'drills' && (
                    <ProcessDrills drills={drills} />
                )}

                {inspectorTab === 'history' && (
                    <TimelineView resourceId={process.id} />
                )}
            </div>
        </InspectorLayout>
    );
};

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    Lock, Send, X, FileText, User, Paperclip, ShieldAlert, Download, ExternalLink, Image, File, Upload, AlertTriangle
} from '../ui/Icons';
import { Dialog } from '@headlessui/react';
import { useStore } from '../../store';
import { Button } from '../ui/button';
import { useZodForm } from '../../hooks/useZodForm';
import { warRoomMessageSchema, WarRoomMessageFormData } from '../../schemas/continuitySchema';
import { useWarRoom } from '../../hooks/incidents/useWarRoom';
import { ErrorLogger } from '../../services/errorLogger';
import { useNavigate } from 'react-router-dom';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { storage } from '../../firebase';
import { Tooltip } from '../ui/Tooltip';

interface WarRoomModalProps {
    isOpen: boolean;
    onClose: () => void;
    incidentId: string;
    incidentTitle: string;
}

// Crisis documents - these are critical documents for incident response
interface CrisisDocument {
    id: string;
    title: string;
    type: 'pca' | 'pra' | 'procedure' | 'contact' | 'playbook';
    url?: string;
    description?: string;
}

const CRISIS_DOCUMENTS: CrisisDocument[] = [
    { id: 'pca-1', title: 'Plan de Continuité (PCA)', type: 'pca', description: 'Plan de continuité d\'activité' },
    { id: 'pra-1', title: 'Plan de Reprise (PRA)', type: 'pra', description: 'Plan de reprise d\'activité' },
    { id: 'contact-1', title: 'Annuaire de Crise', type: 'contact', description: 'Contacts d\'urgence' },
    { id: 'proc-1', title: 'Procédures de Restauration', type: 'procedure', description: 'Procédures techniques' },
    { id: 'playbook-1', title: 'Playbook Incident', type: 'playbook', description: 'Guide de réponse' }
];

export const WarRoomModal: React.FC<WarRoomModalProps> = ({ isOpen, onClose, incidentId, incidentTitle }) => {
    const { user, demoMode } = useStore();
    const navigate = useNavigate();
    const bottomRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const { messages, sendMessage, sendSystemMessage, loading, presence } = useWarRoom(incidentId);

    // Attachment state
    const [pendingAttachments, setPendingAttachments] = useState<File[]>([]);
    const [uploadingAttachment, setUploadingAttachment] = useState(false);

    useEffect(() => {
        if (isOpen) {
            bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
        }
    }, [messages, isOpen]);

    // Send system message when War Room opens
    useEffect(() => {
        if (isOpen && incidentId) {
            // Send a system message indicating the war room was activated
            sendSystemMessage?.(`${user?.displayName || 'Utilisateur'} a rejoint le War Room.`);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen, incidentId]);

    const { register, handleSubmit, reset } = useZodForm({
        schema: warRoomMessageSchema,
        defaultValues: {
            content: ''
        }
    });

    // Handle file selection
    const handleFileSelect = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        if (files.length > 0) {
            // Limit file size to 10MB
            const validFiles = files.filter(f => f.size <= 10 * 1024 * 1024);
            if (validFiles.length < files.length) {
                ErrorLogger.warn('Some files were too large (max 10MB)', 'WarRoomModal.handleFileSelect');
            }
            setPendingAttachments(prev => [...prev, ...validFiles]);
        }
        // Reset input
        if (e.target) e.target.value = '';
    }, []);

    // Remove pending attachment
    const removePendingAttachment = useCallback((index: number) => {
        setPendingAttachments(prev => prev.filter((_, i) => i !== index));
    }, []);

    // Upload file to storage
    const uploadFile = useCallback(async (file: File): Promise<{ name: string; url: string; type: string }> => {
        if (demoMode) {
            // Demo mode: return fake URL
            return {
                name: file.name,
                url: `https://demo.example.com/files/${file.name}`,
                type: file.type
            };
        }

        const fileRef = ref(storage, `war_room/${incidentId}/${Date.now()}_${file.name}`);
        await uploadBytes(fileRef, file);
        const url = await getDownloadURL(fileRef);
        return { name: file.name, url, type: file.type };
    }, [incidentId, demoMode]);

    const onSubmit = async (data: WarRoomMessageFormData) => {
        if (!data.content.trim() && pendingAttachments.length === 0) return;

        try {
            setUploadingAttachment(true);

            // Upload any pending attachments
            const attachments = await Promise.all(
                pendingAttachments.map(file => uploadFile(file))
            );

            await sendMessage(data.content, attachments.length > 0 ? attachments : undefined);
            reset();
            setPendingAttachments([]);
        } catch (error) {
            ErrorLogger.error(error, 'WarRoomModal.onSubmit');
        } finally {
            setUploadingAttachment(false);
        }
    };

    // Navigate to document
    const openDocument = useCallback((doc: CrisisDocument) => {
        // In a real app, this would navigate to the actual document
        // For now, navigate to the documents section with a filter
        if (doc.type === 'pca' || doc.type === 'pra') {
            navigate('/continuity?tab=pra');
        } else if (doc.type === 'contact') {
            navigate('/team');
        } else if (doc.type === 'playbook') {
            navigate('/incidents?tab=playbooks');
        } else {
            navigate('/documents?search=' + encodeURIComponent(doc.title));
        }
        // Keep war room open in background (don't close)
    }, [navigate]);

    // Get file icon based on type
    const getFileIcon = (type: string) => {
        if (type.startsWith('image/')) return <Image className="w-4 h-4" />;
        if (type.includes('pdf')) return <FileText className="w-4 h-4" />;
        return <File className="w-4 h-4" />;
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <Dialog static open={isOpen} onClose={onClose} className="relative z-modal">
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        className="fixed inset-0 bg-black/90 backdrop-blur-sm"
                    />

                    <div className="fixed inset-0 flex items-center justify-center p-4">
                        <Dialog.Panel
                            as={motion.div}
                            initial={{ scale: 0.95, opacity: 0, y: 20 }}
                            animate={{ scale: 1, opacity: 1, y: 0 }}
                            exit={{ scale: 0.95, opacity: 0, y: 20 }}
                            className="bg-slate-900 w-full max-w-[95vw] md:max-w-6xl h-[90vh] md:h-[85vh] rounded-3xl border border-red-500/30 shadow-[0_0_100px_rgba(239,68,68,0.2)] flex overflow-hidden flex-col md:flex-row relative"
                        >
                            {/* CRT/Scanline Overlay */}
                            <div className="absolute inset-0 pointer-events-none bg-[repeating-linear-gradient(transparent,transparent_2px,rgba(0,0,0,0.1)_3px)] opacity-60 z-decorator mix-blend-overlay" />

                            {/* Left Panel: Context & Docs */}
                            <div className="w-full md:w-1/3 border-b md:border-b-0 md:border-r border-white/10 bg-black/20 flex flex-col">
                                <div className="p-6 border-b border-white/10 bg-red-950/20">
                                    <div className="flex items-center gap-3 text-red-500 mb-2">
                                        <Lock className="w-5 h-5 animate-pulse" />
                                        <span className="text-xs font-mono font-bold tracking-[0.2em] uppercase">Top Secret // Eyes Only</span>
                                    </div>
                                    <Dialog.Title as="h2" className="text-2xl font-black text-white uppercase tracking-tight">War Room</Dialog.Title>
                                    <p className="text-red-400 text-sm font-mono mt-1 break-all">REF: {incidentId}</p>
                                    <p className="text-muted-foreground text-xs mt-2 line-clamp-2">{incidentTitle}</p>
                                </div>

                                <div className="flex-1 overflow-y-auto p-6 space-y-6">
                                    {/* Critical Docs */}
                                    <div>
                                        <h3 className="text-xs font-bold text-slate-500 dark:text-slate-300 uppercase tracking-wider mb-4 flex items-center gap-2">
                                            <FileText className="w-4 h-4" /> Documents Critiques
                                        </h3>
                                        <div className="space-y-2">
                                            {CRISIS_DOCUMENTS.map((doc) => (
                                                <button
                                                    key={doc.id}
                                                    onClick={() => openDocument(doc)}
                                                    className="group w-full flex items-center justify-between p-3 rounded-xl bg-white/5 border border-white/5 hover:border-red-500/30 hover:bg-white/10 cursor-pointer transition-all text-left"
                                                >
                                                    <div className="flex items-center gap-3">
                                                        <div className="p-2 rounded-lg bg-slate-800 text-slate-400 group-hover:text-white transition-colors">
                                                            <FileText className="w-4 h-4" />
                                                        </div>
                                                        <div>
                                                            <span className="text-sm font-medium text-slate-300 group-hover:text-white block">{doc.title}</span>
                                                            {doc.description && (
                                                                <span className="text-xs text-slate-500">{doc.description}</span>
                                                            )}
                                                        </div>
                                                    </div>
                                                    <Tooltip content="Ouvrir" position="left">
                                                        <span className="p-2 text-muted-foreground hover:text-white rounded-lg hover:bg-white/10">
                                                            <ExternalLink className="w-4 h-4" />
                                                        </span>
                                                    </Tooltip>
                                                </button>
                                            ))}
                                        </div>
                                    </div>

                                    {/* Quick Actions */}
                                    <div>
                                        <h3 className="text-xs font-bold text-slate-500 dark:text-slate-300 uppercase tracking-wider mb-4 flex items-center gap-2">
                                            <AlertTriangle className="w-4 h-4" /> Actions Rapides
                                        </h3>
                                        <div className="space-y-2">
                                            <button
                                                onClick={() => navigate(`/incidents/${incidentId}`)}
                                                className="w-full flex items-center gap-3 p-3 rounded-xl bg-red-50 dark:bg-red-900/30 border border-red-500/20 hover:bg-red-500/20 transition-all text-left"
                                            >
                                                <AlertTriangle className="w-4 h-4 text-red-500" />
                                                <span className="text-sm font-medium text-red-400">Voir l'incident</span>
                                            </button>
                                            <button
                                                onClick={() => navigate('/incidents?action=escalate')}
                                                className="w-full flex items-center gap-3 p-3 rounded-xl bg-orange-500/10 border border-orange-500/20 hover:bg-orange-500/20 transition-all text-left"
                                            >
                                                <Upload className="w-4 h-4 text-orange-500" />
                                                <span className="text-sm font-medium text-orange-400">Escalader</span>
                                            </button>
                                        </div>
                                    </div>

                                    {/* Active Users - Real-time Presence */}
                                    <div>
                                        <h3 className="text-xs font-bold text-slate-500 dark:text-slate-300 uppercase tracking-wider mb-4 flex items-center gap-2">
                                            <User className="w-4 h-4" /> En Ligne ({presence.length})
                                        </h3>
                                        <div className="space-y-2">
                                            {presence.length === 0 ? (
                                                <p className="text-xs text-slate-500">Aucun participant</p>
                                            ) : (
                                                presence.map((p) => (
                                                    <div key={p.id} className="flex items-center gap-3 p-2 rounded-lg bg-white/5">
                                                        <div className="relative">
                                                            {p.photoURL ? (
                                                                <img
                                                                    src={p.photoURL}
                                                                    alt={p.displayName}
                                                                    className="w-8 h-8 rounded-full object-cover border-2 border-emerald-500"
                                                                />
                                                            ) : (
                                                                <div className="w-8 h-8 rounded-full bg-slate-700 border-2 border-emerald-500 flex items-center justify-center text-xs text-white">
                                                                    {p.displayName?.charAt(0) || 'U'}
                                                                </div>
                                                            )}
                                                            <div className="absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full bg-emerald-500 border-2 border-slate-900" />
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <p className="text-sm font-medium text-white truncate">
                                                                {p.displayName}
                                                                {p.id === user?.uid && <span className="text-slate-400 ml-1">(vous)</span>}
                                                            </p>
                                                            <p className="text-xs text-slate-500 dark:text-slate-300 capitalize">{p.role}</p>
                                                        </div>
                                                    </div>
                                                ))
                                            )}
                                        </div>
                                    </div>
                                </div>
                            </div>

                            {/* Right Panel: Chat */}
                            <div className="flex-1 flex flex-col bg-slate-900/50">
                                {/* Chat Header */}
                                <div className="p-4 border-b border-white/10 flex items-center justify-between">
                                    <div className="flex items-center gap-2">
                                        <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
                                        <span className="text-xs font-mono text-emerald-500 uppercase">Canal Sécurisé actif</span>
                                    </div>
                                    <Button variant="ghost" size="sm" onClick={onClose} className="hover:bg-white/10 text-muted-foreground hover:text-white" aria-label="Fermer le War Room">
                                        <X className="w-5 h-5" aria-hidden="true" />
                                    </Button>
                                </div>

                                {/* Messages Area */}
                                <div className="flex-1 overflow-y-auto p-6 space-y-4 font-mono text-sm max-h-[60vh] md:max-h-none">
                                    {messages.length === 0 && !loading && (
                                        <div className="flex flex-col items-center justify-center h-full text-slate-500 dark:text-slate-300 gap-2">
                                            <ShieldAlert className="w-12 h-12 opacity-20" />
                                            <p>Aucun message. Le canal est ouvert.</p>
                                        </div>
                                    )}

                                    {messages.map((msg) => (
                                        <motion.div
                                            initial={{ opacity: 0, y: 10 }}
                                            animate={{ opacity: 1, y: 0 }}
                                            key={msg.id}
                                            className={`flex ${msg.isSystem ? 'justify-center' : msg.senderId === user?.uid ? 'justify-end' : 'justify-start'}`}
                                        >
                                            {msg.isSystem ? (
                                                <span className="px-3 py-1 rounded-full bg-red-950/50 border border-red-500/20 text-red-500 text-xs">
                                                    {msg.content}
                                                </span>
                                            ) : (
                                                <div className={`max-w-[80%] p-4 rounded-2xl border ${msg.senderId === user?.uid
                                                    ? 'bg-blue-600/20 border-blue-500/30 text-blue-100 rounded-tr-none'
                                                    : 'bg-slate-800 border-white/10 text-slate-300 rounded-tl-none'
                                                    }`}>
                                                    <div className="flex items-center gap-2 mb-1 opacity-60 text-xs">
                                                        <span className="font-bold">{msg.sender}</span>
                                                        <span>•</span>
                                                        <span>{msg.role}</span>
                                                        <span>•</span>
                                                        <span>{msg.timestamp?.toLocaleTimeString ? msg.timestamp.toLocaleTimeString() : ''}</span>
                                                    </div>
                                                    {msg.content && <p className="whitespace-pre-wrap">{msg.content}</p>}
                                                    {/* Attachments */}
                                                    {msg.attachments && msg.attachments.length > 0 && (
                                                        <div className="mt-2 space-y-1">
                                                            {msg.attachments.map((att, idx) => (
                                                                <a
                                                                    key={idx}
                                                                    href={att.url}
                                                                    target="_blank"
                                                                    rel="noopener noreferrer"
                                                                    className="flex items-center gap-2 p-2 rounded-lg bg-black/20 hover:bg-black/40 transition-colors text-xs"
                                                                >
                                                                    {getFileIcon(att.type)}
                                                                    <span className="truncate flex-1">{att.name}</span>
                                                                    <Download className="w-3 h-3 opacity-60" />
                                                                </a>
                                                            ))}
                                                        </div>
                                                    )}
                                                </div>
                                            )}
                                        </motion.div>
                                    ))}
                                    <div ref={bottomRef} />
                                </div>

                                {/* Input Area */}
                                <div className="p-4 border-t border-white/10 bg-black/20">
                                    {/* Pending Attachments Preview */}
                                    {pendingAttachments.length > 0 && (
                                        <div className="mb-3 flex flex-wrap gap-2">
                                            {pendingAttachments.map((file, idx) => (
                                                <div
                                                    key={idx}
                                                    className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-blue-500/20 border border-blue-500/30 text-sm"
                                                >
                                                    {getFileIcon(file.type)}
                                                    <span className="truncate max-w-[100px] sm:max-w-[150px] text-blue-200">{file.name}</span>
                                                    <button
                                                        type="button"
                                                        onClick={() => removePendingAttachment(idx)}
                                                        className="text-blue-300 hover:text-white ml-1"
                                                    >
                                                        <X className="w-3 h-3" />
                                                    </button>
                                                </div>
                                            ))}
                                        </div>
                                    )}

                                    <form onSubmit={handleSubmit(onSubmit)} className="flex gap-4">
                                        {/* Hidden file input */}
                                        <input
                                            ref={fileInputRef}
                                            type="file"
                                            multiple
                                            accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,.txt,.csv"
                                            onChange={handleFileSelect}
                                            className="hidden"
                                        />

                                        <Tooltip content="Joindre un fichier (max 10MB)" position="top">
                                            <Button
                                                type="button"
                                                variant="ghost"
                                                onClick={() => fileInputRef.current?.click()}
                                                className="text-muted-foreground hover:text-white"
                                                aria-label="Joindre un fichier"
                                            >
                                                <Paperclip className="w-5 h-5" />
                                            </Button>
                                        </Tooltip>

                                        <input
                                            aria-label="Message de war room"
                                            placeholder="Tapez un message chiffré..."
                                            className="flex-1 bg-transparent border-none text-white placeholder-slate-500 focus:ring-0 font-mono"
                                            autoFocus
                                            {...register('content')}
                                        />

                                        <Button
                                            type="submit"
                                            disabled={loading || uploadingAttachment}
                                            isLoading={loading || uploadingAttachment}
                                            size="icon"
                                            aria-label="Envoyer le message"
                                        >
                                            <Send className="w-4 h-4" />
                                        </Button>
                                    </form>

                                    {/* Encryption indicator */}
                                    <div className="flex items-center gap-2 mt-2 text-xs text-emerald-500/70">
                                        <Lock className="w-3 h-3" />
                                        <span>Chiffrement de bout en bout activé</span>
                                    </div>
                                </div>
                            </div>
                        </Dialog.Panel>
                    </div>
                </Dialog>
            )}
        </AnimatePresence>
    );
};

import React, { useState } from 'react';
import { TlptCampaign } from '../../../types/tlpt';
import { Button } from '../../ui/button';
import { Plus, Shield, Calendar, Users, Target } from '../../ui/Icons';
import { EmptyState } from '../../ui/EmptyState';
import { TLPTInspector } from './TLPTInspector';

interface Props {
    campaigns: TlptCampaign[];
    loading?: boolean;
    onAdd: (data: Partial<TlptCampaign>) => Promise<void>;
    onUpdate: (id: string, data: Partial<TlptCampaign>) => Promise<void>;
    onDelete: (id: string) => Promise<void>;
    canEdit: boolean;
}

export const TlptDashboard: React.FC<Props> = ({ campaigns, loading, onAdd, onUpdate, onDelete, canEdit }) => {
    const [selectedCampaign, setSelectedCampaign] = useState<TlptCampaign | null>(null);
    const [isModalOpen, setIsModalOpen] = useState(false);

    const handleEdit = (campaign: TlptCampaign) => {
        setSelectedCampaign(campaign);
        setIsModalOpen(true);
    };

    const handleCreate = () => {
        setSelectedCampaign(null);
        setIsModalOpen(true);
    };

    const handleSubmit = async (data: Partial<TlptCampaign>) => {
        if (selectedCampaign) {
            await onUpdate(selectedCampaign.id, data);
        } else {
            await onAdd(data);
        }
        setIsModalOpen(false);
    };

    if (loading) return (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
            {[1, 2, 3].map((i) => (
                <div key={i} className="h-48 bg-slate-100 dark:bg-slate-800 rounded-xl animate-pulse" />
            ))}
        </div>
    );

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h3 className="text-lg font-semibold text-slate-900 dark:text-white">Campagnes de Tests de Résilience</h3>
                    <p className="text-sm text-slate-500">Gestion des tests d'intrusion avancés (TLPT) et Red Teaming.</p>
                </div>
                {canEdit && (
                    <Button onClick={handleCreate}>
                        <Plus className="w-4 h-4 mr-2" />
                        Nouvelle Campagne
                    </Button>
                )}
            </div>

            {campaigns.length === 0 ? (
                <EmptyState
                    icon={Shield}
                    title="Aucune campagne TLPT"
                    description="Planifiez votre première campagne de test de résilience."
                    actionLabel={canEdit ? "Planifier une campagne" : undefined}
                    onAction={canEdit ? handleCreate : undefined}
                />
            ) : (
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6">
                    {campaigns.map(campaign => (
                        <div
                            key={campaign.id}
                            className="bg-white dark:bg-slate-800 rounded-xl p-5 border border-slate-200 dark:border-slate-700 shadow-sm hover:shadow-md transition-shadow cursor-pointer group"
                            onClick={() => canEdit && handleEdit(campaign)}
                        >
                            <div className="flex justify-between items-start mb-4">
                                <div className={`px-2 py-1 text-xs font-semibold rounded-full ${getStatusColor(campaign.status)}`}>
                                    {campaign.status}
                                </div>
                                <span className="text-xs text-muted-foreground">
                                    {campaign.methodology}
                                </span>
                            </div>

                            <h4 className="font-bold text-slate-900 dark:text-white mb-2 group-hover:text-brand-500 transition-colors">
                                {campaign.name}
                            </h4>

                            <div className="space-y-2 text-sm text-slate-600 dark:text-muted-foreground">
                                <div className="flex items-center gap-2">
                                    <Target className="w-4 h-4 text-muted-foreground" />
                                    <span className="truncate">{campaign.scope}</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    <Users className="w-4 h-4 text-muted-foreground" />
                                    <span>{campaign.provider}</span>
                                </div>
                                <div className="flex items-center gap-2">
                                    <Calendar className="w-4 h-4 text-muted-foreground" />
                                    <span>
                                        {campaign.startDate ? new Date(((campaign.startDate as unknown) as { seconds: number }).seconds ? ((campaign.startDate as unknown) as { seconds: number }).seconds * 1000 : campaign.startDate as Date | string | number).toLocaleDateString() : 'N/A'}
                                    </span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {isModalOpen && (
                <TLPTInspector
                    onClose={() => setIsModalOpen(false)}
                    onUpdate={handleSubmit}
                    campaign={selectedCampaign || undefined}
                    onDelete={onDelete}
                    canEdit={canEdit}
                />
            )}
        </div>
    );
};

function getStatusColor(status: string) {
    switch (status) {
        case 'Planned': return 'bg-blue-100 text-blue-700 dark:text-blue-400 dark:bg-blue-900/30 dark:text-blue-300';
        case 'In Progress': return 'bg-amber-100 text-amber-700 dark:text-amber-400 dark:bg-amber-900/30 dark:text-amber-300';
        case 'Analysis': return 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300';
        case 'Remediation': return 'bg-orange-100 text-orange-700 dark:text-orange-400 dark:bg-orange-900/30 dark:text-orange-300';
        case 'Closed': return 'bg-green-100 text-green-700 dark:text-green-400 dark:bg-green-900/30 dark:text-green-300';
        default: return 'bg-slate-100 dark:bg-slate-800 text-slate-700';
    }
}

import React, { useState } from 'react';
import { TlptCampaign } from '../../../types/tlpt';
import { Vulnerability } from '../../../types/risks';
import { useVulnerabilities } from '../../../hooks/useVulnerabilities';
import { Button } from '../../ui/button';
import { Plus, AlertTriangle, ShieldAlert } from '../../ui/Icons';
import { VulnerabilityForm } from '../../vulnerabilities/VulnerabilityForm';
import { Modal } from '../../ui/Modal';
import { EmptyState } from '../../ui/EmptyState';
import { useStore } from '../../../store'; // For assets

import { useContinuityData } from '../../../hooks/continuity/useContinuityData';

interface TlptFindingsProps {
    campaign: TlptCampaign;
}

export const TlptFindings: React.FC<TlptFindingsProps> = ({ campaign }) => {
    const { vulnerabilities, addVulnerability, updateVulnerability, loading } = useVulnerabilities();
    const { user } = useStore();
    const { assets: continuityAssets } = useContinuityData(user?.organizationId);


    const [isFormOpen, setIsFormOpen] = useState(false);
    const [editingVuln, setEditingVuln] = useState<Vulnerability | undefined>(undefined);

    const findings = vulnerabilities.filter(v => v.relatedTlptCampaignId === campaign.id);

    const handleAddFinding = async (data: Partial<Vulnerability>) => {
        await addVulnerability({
            ...data,
            relatedTlptCampaignId: campaign.id,
            relatedTlptCampaignName: campaign.name,
            source: `TLPT - ${campaign.name}`
        });
        setIsFormOpen(false);
    };

    const handleUpdateFinding = async (data: Partial<Vulnerability>) => {
        if (editingVuln?.id) {
            await updateVulnerability(editingVuln.id, data);
            setEditingVuln(undefined);
            setIsFormOpen(false);
        }
    };

    const openEdit = (vuln: Vulnerability) => {
        setEditingVuln(vuln);
        setIsFormOpen(true);
    };

    return (
        <div className="space-y-4">
            <div className="flex justify-between items-center">
                <h3 className="text-lg font-medium text-slate-900 dark:text-white">
                    Constatations ({findings.length})
                </h3>
                <Button onClick={() => { setEditingVuln(undefined); setIsFormOpen(true); }} size="sm" className="bg-brand-600 text-white">
                    <Plus className="w-4 h-4 mr-2" />
                    Ajouter une constatation
                </Button>
            </div>

            {loading ? (
                <div className="p-4 text-center text-slate-500">Chargement...</div>
            ) : findings.length === 0 ? (
                <EmptyState
                    icon={ShieldAlert}
                    title="Aucune constatation"
                    description="Ajoutez les vulnérabilités identifiées durant cette campagne."
                    actionLabel="Ajouter"
                    onAction={() => setIsFormOpen(true)}
                />
            ) : (
                <div className="grid gap-3">
                    {findings.map(vuln => (
                        <div key={vuln.id}
                            className="p-4 rounded-xl border border-slate-200 dark:border-white/10 bg-white dark:bg-white/5 hover:border-brand-500 transition-colors cursor-pointer group"
                            onClick={() => openEdit(vuln)}
                        >
                            <div className="flex justify-between items-start">
                                <div>
                                    <h4 className="font-medium text-slate-900 dark:text-white flex items-center gap-2">
                                        <AlertTriangle className={`w-4 h-4 ${vuln.severity === 'Critical' ? 'text-red-500' : 'text-amber-500'}`} />
                                        {vuln.title || vuln.cveId}
                                    </h4>
                                    <p className="text-sm text-slate-500 dark:text-slate-300 mt-1 line-clamp-2">{vuln.description}</p>
                                </div>
                                <div className="flex flex-col items-end gap-2">
                                    <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${vuln.status === 'Resolved' || vuln.status === 'Patch Applied'
                                        ? 'bg-green-100 text-green-700 dark:text-green-400 dark:bg-green-900/30 dark:text-green-400'
                                        : 'bg-blue-100 text-blue-700 dark:text-blue-400 dark:bg-blue-900/30 dark:text-blue-400'
                                        }`}>
                                        {vuln.status}
                                    </span>
                                    <span className="text-xs text-muted-foreground">Score: {vuln.score}</span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            <Modal
                isOpen={isFormOpen}
                onClose={() => setIsFormOpen(false)}
                title={editingVuln ? "Modifier la constatation" : "Nouvelle constatation"}
                maxWidth="2xl"
            >
                <VulnerabilityForm
                    initialData={editingVuln}
                    onSubmit={editingVuln ? handleUpdateFinding : handleAddFinding}
                    onCancel={() => setIsFormOpen(false)}
                    assets={continuityAssets || []}
                    isLoading={false}
                    projects={[]} // Optional
                    users={[]} // Optional
                />
            </Modal>
        </div>
    );
};
